\displaystyle{\begin{aligned}
   \frac{3}{10} + \frac{1}{6}
        \amp = \frac{9}{30} + \frac{5}{30} \\
        \amp = \frac{9 + 5}{30} \\
        \amp = \frac{14}{30} \amp \hbox{We can reduce this by dividing 2 into both the numerator and the denominator.
}\\
        \amp = \frac{7}{15}
\end{aligned}
    }
